import{c as a,Q as e,j as r,m as o}from"./chunks/framework.BA1dEi98.js";const u=JSON.parse('{"title":"About LibrisLog","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1779871928000}'),i={name:"about.md"};function n(s,t,d,l,h,c){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="about-librislog" tabindex="-1">About LibrisLog <a class="header-anchor" href="#about-librislog" aria-label="Permalink to &quot;About LibrisLog&quot;">​</a></h1><p>LibrisLog is a <strong>multi-user book tracking web application</strong> designed for readers who want to organize their library, track reading progress, and gain insights into their reading habits.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>Library Management</strong>: Organize books into four reading statuses — Want to Read, Currently Reading, Read, and Did Not Finish</li><li><strong>Book Import</strong>: Search Open Library, Google Books, and Hardcover.app. Scan ISBN barcodes for quick lookup</li><li><strong>Reading Progress</strong>: Track pages read over time with a visual timeline and calendar heatmap</li><li><strong>Statistics Dashboard</strong>: Charts showing pages read per month, books finished, language distribution, and more</li><li><strong>Cover Management</strong>: Automatic cover image scraping from multiple sources with manual override</li><li><strong>Data Portability</strong>: Export/import library as JSON or CSV. Full backup and restore functionality</li><li><strong>REST API</strong>: Full API with OpenAPI documentation for programmatic access</li><li><strong>Multilingual</strong>: English and German UI support</li><li><strong>Themes</strong>: Light, dark, and custom DaisyUI themes with persistent preferences</li></ul><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Frontend</td><td>SvelteKit + DaisyUI + Tailwind CSS</td></tr><tr><td>Backend</td><td>FastAPI + SQLModel + Alembic</td></tr><tr><td>Database</td><td>SQLite</td></tr><tr><td>Search</td><td>Open Library, Google Books, Hardcover.app</td></tr><tr><td>Charts</td><td>Chart.js</td></tr><tr><td>Icons</td><td>Lucide</td></tr></tbody></table><h2 id="author" tabindex="-1">Author <a class="header-anchor" href="#author" aria-label="Permalink to &quot;Author&quot;">​</a></h2><p>Created and maintained by <a href="https://github.com/codebude" target="_blank" rel="noreferrer">Raffael Herrmann</a>.</p><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>Released under the MIT License.</p>',10)])])}const b=a(i,[["render",n]]);export{u as __pageData,b as default};
